// Verify if the editor has text in it

const submitButton = document.querySelector('.create-post-form>button[type="submit"]');

function checkEditorContent() {
    if (submitButton) {
        if (postFormEditor.html) {
            let editorContent = postFormEditor.html.get(true);
            submitButton.disabled = editorContent.trim().length <= 0;
        } else {
            submitButton.disabled = true;
        }
    }
}

checkEditorContent();

// Post Audience Section

const postFormAudienceSelect = document.querySelector('#post_audienceType'),
    postAudience = document.querySelector('.post-form-audience'),
    postAudienceHeader = document.querySelector('.post-form-audience h2'),
    postFormAudienceUsers = document.querySelector('#post_audience_user'),
    postFormAudienceSave = document.querySelector('.post-form-audience .button');

if (postAudience) {
    postFormAudienceSelect.addEventListener('change', function (event) {
        const selectedOption = event.target.options[event.target.selectedIndex];

        if (selectedOption.innerText.includes('Friends except...') || selectedOption.innerText.includes('Specific friends')) {
            postAudienceHeader.innerText = selectedOption.innerText;
            postAudience.style.display = "block";
            postFormAudienceUsers.selectedIndex = -1;
        } else {
            postAudience.style.display = "none";
            postFormAudienceUsers.selectedIndex = -1;
        }

        postFormAudienceUsers.selectedIndex = -1;
    })

    postFormAudienceSave.addEventListener('click', function (evt) {
        postAudience.style.display = "none";
    })
}

const createPostFormTitle = document.querySelector('.create-post-form-container h2');

if (submitButton && createPostFormTitle && createPostFormTitle.innerText === 'Update Post') {
    submitButton.disabled = false;

    if (postFormAudienceSelect.value.includes('friends_except') || postFormAudienceSelect.value.includes('specific_friends')) {
        postAudience.style.display = "block";
        console.log(1);
    }

    console.log(postFormAudienceSelect.value);
}

//Comment Post Form

const newestCommentsFilter = document.querySelector('.newest-comments'),
    oldestCommentsFilter = document.querySelector('.oldest-comments'),
    commentsBlock = document.querySelector('.comments');

// Check if we're on the post page
if (!fakeUploadPostInput && commentsBlock) {
    const commentFormEditor = new FroalaEditor('.comment-input', {
        toolbarInline: true,
        toolbarVisibleWithoutSelection: true,
        charCounterCount: false,
        imageUploadMethod: 'POST',
        imageUploadURL: '/comment/upload/images',
        imageAllowedTypes: ['jpeg', 'jpg', 'png'],
        imageMaxSize: 1024 * 1024 * 3,
        videoUploadMethod: 'POST',
        videoUploadURL: '/comment/upload/videos',
        videoAllowedTypes: ['mp4', 'gif', 'ogg', 'webm'],
        videoMaxSize: 1024 * 1024 * 10,
        fileUploadMethod: 'POST',
        fileUploadURL: '/comment/upload/files',
        fileAllowedTypes: ['application/pdf'],
        fileMaxSize: 1024 * 1024 * 5,
        events: {
            contentChanged: checkCommentFormContent
        },
        saveURL: '/post/create',
    }),
        commentFormButton = document.querySelector('.comment-bar form svg');

    function submitComment() {
        const url = "/comment/create";
        const data = {
            content: commentFormEditor.html.get(true),
            post_id: commentFormButton.getAttribute("data-post-id")
        };

        fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-Requested-With': 'XMLHttpRequest' // Important for Symfony to detect AJAX request
            },
            body: JSON.stringify(data)
        })
            .then(response => response.json())
            .then(data => {
                console.log(data);
                return true;
            })
            .catch((error) => {
                console.error('Error:', error);
                return false;
            })
    }


    function checkCommentFormContent() {
        if (commentFormEditor.html) {
            let editorContent = commentFormEditor.html.get(true);

            if (editorContent.trim().length <= 0) {
                commentFormButton.removeEventListener('click', submitComment);
                commentFormButton.style.cursor = "initial";
                commentFormButton.style.color = "inherit";
            } else {
                commentFormButton.addEventListener('click', submitComment);
                commentFormButton.style.color = "var(--principal-color)";
                commentFormButton.style.cursor = "pointer";
                console.log('Fuck You');
            }
        } else {
            commentFormButton.removeEventListener('click', submitComment);
            commentFormButton.style.cursor = "initial";
            commentFormButton.style.color = "inherit";
        }
    }

    /**
     * @param condition {string}
     * @returns {any}
     */
    function fetchComments(condition = "oldest") {
        const url = "/comment/fetch";
        const data = {
            post_id: commentFormButton.getAttribute("data-post-id"),
            condition: condition
        };

        return fetch(url, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'X-Requested-With': 'XMLHttpRequest' // Important for Symfony to detect AJAX request
            },
            body: JSON.stringify(data)
        })
            .then(response => response.json())
            .then(data => {
                console.log(data);
                return data;
            })
            .catch((error) => {
                console.error('Error:', error);
                return false;
            })
    }

    async function displayComments(condition = "oldest") {
        const data = await fetchComments(condition);

        if (data) {
            for (const datum of data) {
                let commentBlock = document.createElement('div');
                commentBlock.classList.add("comment");

                let content = `<div class="comment-content" id="comment-content-${datum.id}">${datum.content}</div>`;
                commentBlock.innerHTML += content;

                commentsBlock.appendChild(commentBlock);

                console.log(datum);
                console.log(datum.content);
            }
        }
    }

    // Initial Check
    checkCommentFormContent();

    commentFormButton.addEventListener('click', function () {
        submitComment(commentFormEditor, this)
    });

    // Initial display of Comments
    displayComments();

    newestCommentsFilter.addEventListener('click', function () {
        const commentBlocks = document.querySelectorAll('.comment');

        for (const commentBlock of commentBlocks) {
            commentBlock.remove();
        }

        displayComments("newest");
    });
}